// pages/index.js
import { useState, useEffect, useCallback, useRef } from "react";
import Head from "next/head";
import { ArrowLeft2, PlayCircle } from "iconsax-react";
import HomeLayout from "../layouts/Layout"; // فرض کردم Layout تو src/layouts/Layout هست
import CategoryChips from "../components/CategoryChips";
import VideoGrid from "../components/VideoGrid";
import VideoSkeleton from "../components/VideoSkeleton";
import { serverAxios } from "../lib/serverAxios";
import { useLandingChannels } from "../hooks/useLandingChannels";
import { useInfiniteLandingVideos } from "../hooks/useInfiniteLandingVideos";
import { useRouter } from "next/router";
import { getHomeNavigationState } from "../next/navigationState";

const PAGE_SIZE = 25;

// ===== Map API response =====
const mapPaginatedResponse = (res) => {
  const payload = res?.data ?? {};

  return {
    items: payload?.data ?? [],
    totalPages: payload?.meta?.last_page ?? 1,
    totalItems: payload?.meta?.total ?? (payload?.data?.length ?? 0),
  };
};

// ===== SSR =====
export async function getServerSideProps() {
  try {
    const [channelsRes, videosRes] = await Promise.all([
      serverAxios.get("/api/landing/channels?page=1&per_page=10"),
      serverAxios.get("/api/landing/videos?page=1&per_page=25"),
    ]);

    return {
      props: {
        initialChannels: mapPaginatedResponse(channelsRes),
        initialVideos: mapPaginatedResponse(videosRes),
      },
    };
  } catch (error) {
    console.error("Error fetching SSR data:", error);
    return {
      props: {
        initialChannels: { items: [], totalPages: 1, totalItems: 0 },
        initialVideos: { items: [], totalPages: 1, totalItems: 0 },
      },
    };
  }
}

// ===== Component =====
export default function Home({ initialChannels, initialVideos }) {
  const router = useRouter();
  const [activeChannelId, setActiveChannelId] = useState(null);
  const loadMoreRef = useRef(null);
  const siteUrl = process.env.NEXT_PUBLIC_SITE_URL || "https://example.com";

  // ===== Channels =====
  const {
    data: channelsData,
    isLoading: channelsLoading,
    refetch: channelsRefetch,
  } = useLandingChannels(1, initialChannels);

  const channelsList = Array.isArray(channelsData?.items)
    ? channelsData.items
    : [];

  // ===== Videos =====
  const {
    data: videosData,
    isLoading: videosLoading,
    isError: videosError,
    isFetchingNextPage,
    hasNextPage,
    fetchNextPage,
    refetch,
  } = useInfiniteLandingVideos(activeChannelId, PAGE_SIZE, {
    pages: [initialVideos],
    pageParams: [1],
  });

  const videosList = videosData?.pages
    ? videosData.pages.flatMap((p) => p.items || [])
    : [];

  const activeChannelName = channelsList.find(
    (c) => c.id === activeChannelId
  )?.name;

  // ===== Handlers =====
  const handleChannelSelect = useCallback((id) => {
    setActiveChannelId(id);
  }, []);

  const handleRefresh = useCallback(() => {
    refetch();
  }, [refetch]);

  // ===== Set activeChannelId from router or transient state =====
  useEffect(() => {
    const queryChannelId =
      typeof router.query?.channelId === "string" ? router.query.channelId : null;
    const transientChannelId = getHomeNavigationState();
    const nextChannelId = queryChannelId || transientChannelId;

    if (nextChannelId) {
      setActiveChannelId(nextChannelId);
    }
  }, [router.query?.channelId]);

  // ===== Infinite scroll =====
  useEffect(() => {
    const sentinel = loadMoreRef.current;
    if (!sentinel || !hasNextPage) return;

    const observer = new IntersectionObserver(
      (entries) => {
        const [entry] = entries;
        if (entry?.isIntersecting && !isFetchingNextPage) {
          fetchNextPage();
        }
      },
      { root: null, rootMargin: "300px 0px", threshold: 0.1 }
    );

    observer.observe(sentinel);
    return () => observer.disconnect();
  }, [fetchNextPage, hasNextPage, isFetchingNextPage, videosList.length]);

  // ===== Loading state for channels =====
  if (channelsLoading && !channelsData) {
    return (
      <HomeLayout>
        <div className="min-h-screen bg-gradient-to-b from-slate-50 to-white">
          <div className="mx-auto max-w-7xl px-3 sm:px-4 md:px-6 py-6 sm:py-8">
            <VideoSkeleton count={12} />
          </div>
        </div>
      </HomeLayout>
    );
  }

  const showInitialLoading = videosLoading && videosList.length === 0;

  return (
    <HomeLayout>
      <Head>
        <title>اربعین تی وی - تلویزیون اینترنتی جبهه مقاومت</title>
        <meta
          name="description"
          content="تماشای ویدیوهای اربعین و جبهه مقاومت در اربعین تی وی"
        />
        <meta property="og:title" content="اربعین تی وی" />
        <meta
          property="og:description"
          content="تماشای ویدیوهای اربعین و جبهه مقاومت"
        />
        <meta property="og:image" content="/vite.svg" />
        <meta name="twitter:card" content="summary_large_image" />
        <link rel="canonical" href={`${siteUrl}/`} />
      </Head>

      <div className="min-h-screen bg-gradient-to-b from-slate-50 to-white">
        <div className="mx-auto max-w-7xl px-3 sm:px-4 md:px-6 py-6 sm:py-8">
          {/* Channels */}
          <div className="sticky top-[57px] sm:top-[61px] md:top-[73px] z-40 -mx-3 sm:-mx-4 md:-mx-6 px-3 sm:px-4 md:px-6 py-3 backdrop-blur-md border-b border-slate-200/80 mb-6">
            <CategoryChips
              channels={channelsList}
              activeChannelId={activeChannelId}
              onSelect={handleChannelSelect}
              isLoading={channelsLoading}
              isRefetch={channelsRefetch}
            />
          </div>

          {/* Active channel banner */}
          {activeChannelId && (
            <div className="flex items-center justify-between gap-3 px-4 py-3 rounded-2xl bg-indigo-50 border border-indigo-100 shadow-sm mb-6">
              <span className="text-sm text-slate-600 flex items-center gap-2">
                <ArrowLeft2 size={16} className="text-slate-400" />
                نمایش ویدیوهای{" "}
                <strong className="text-slate-900">
                  {activeChannelName ||
                    videosList[0]?.channel_name ||
                    "کانال"}
                </strong>
              </span>
            </div>
          )}

          {/* Videos */}
          {showInitialLoading ? (
            <div className="mt-6">
              <VideoSkeleton count={PAGE_SIZE} />
            </div>
          ) : videosError ? (
            <div className="flex flex-col items-center justify-center py-16 px-4 rounded-2xl bg-slate-50 border border-slate-200">
              <div className="w-14 h-14 rounded-full bg-red-100 flex items-center justify-center mb-4">
                <span className="text-2xl">⚠</span>
              </div>
              <p className="text-red-600 font-medium mb-2">خطا در دریافت ویدیوها</p>
              <button
                onClick={handleRefresh}
                className="text-indigo-600 hover:text-indigo-700 font-medium px-4 py-2 border border-indigo-200 rounded-xl hover:bg-indigo-50 transition-all"
              >
                تلاش مجدد
              </button>
            </div>
          ) : videosList.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-20 px-4 rounded-2xl bg-slate-50 border border-slate-200 border-dashed">
              <div className="w-20 h-20 rounded-2xl bg-gradient-to-br from-orange-100 to-orange-200 flex items-center justify-center mb-6 shadow-lg">
                <PlayCircle size={40} color="#f97316" />
              </div>
              <h3 className="text-lg font-bold text-slate-900 mb-2">
                {activeChannelId ? "ویدیویی یافت نشد" : "شروع کنید!"}
              </h3>
              <p className="text-slate-600 text-center max-w-md">
                {activeChannelId
                  ? "در این کانال فعلاً ویدیویی موجود نیست."
                  : "کانالی انتخاب کنید تا ویدیوهایش را ببینید."}
              </p>
            </div>
          ) : (
            <section>
              <div className="pb-8">
                <VideoGrid items={videosList} />
              </div>
              <div ref={loadMoreRef} className="flex justify-center py-4 min-h-16">
                {isFetchingNextPage ? (
                  <div className="w-full">
                    <VideoSkeleton count={Math.min(8, PAGE_SIZE)} />
                  </div>
                ) : hasNextPage ? (
                  <span className="text-sm text-slate-500">
                    برای بارگذاری ویدیوهای بیشتر اسکرول کنید.
                  </span>
                ) : (
                  <span className="text-sm text-slate-400">
                    همه ویدیوها نمایش داده شدند.
                  </span>
                )}
              </div>
            </section>
          )}
        </div>
      </div>
    </HomeLayout>
  );
}